};

scwin.f_PopUp = async function(disGubun, chgGubun) {
    if (ds_srList.getRowPosition() == null) ds_srList.setRowPosition(0);

    const fieldMappings = {
        "Shipper": { codeField: "hhscd", dataFields: ["hhscd", "hhs1", "hhs2", "hhs3", "hhs4", "hhs5", "hhsKId", "hhshrgno"] },
        "Consignee": { codeField: "hhccd", dataFields: ["hhccd", "hhc1", "hhc2", "hhc3", "hhc4", "hhc5", "hhcKId", "hhcnrgno"] },
        "Notify": { codeField: "hhncd", dataFields: ["hhncd", "hhn1", "hhn2", "hhn3", "hhn4", "hhn5", "hhnKId", "hhntrgno"] },
        "Liner": { codeField: "hhliner", dataFields: ["hhliner", "hhliner1", "hhliner2", "hhliner3", "hhliner4", "hhliner5", "hhlinerKId", "hhlnrgno", "hhlinerattn", "hhlinerattnnm", null, null, null, null, "ediVersion", "scacCd", "lloydsCd"] }
    };

    const opts = {
        id: "se_116_01_01p",
        popupName: "S/R Customer List Popup",
        modal: true,
        type: "browserPopup",
        width: 1530,
        height: 700,
        title: "S/R Customer List Popup"
    };

    let targetRowIndex = 0;    

    switch (disGubun) {
        case "Shipper":
        case "Consignee":
        case "Notify":
        case "Liner":
            let mapping = fieldMappings[disGubun];	// 매핑된 필드 정보 가져오기
            let data = {"clntNo": ds_srList.getCellData(targetRowIndex, mapping.codeField)};	// 팝업에 전달할 데이터 준비
            let rtnData = await $c.win.openPopup("/ui/il/seaout/sosr/se_116_01_01p.xml", opts, data);
            if (rtnData != null && rtnData.length > 0) {
				//데이터 설정
                mapping.dataFields.forEach((field, index) => {
                    if (field != null) {
                        ds_srList.setCellData(targetRowIndex, field, rtnData[index]);
                    }
                });
            }
            break;
        case "LinerPic":
            let pParam = ds_srList.getCellData(targetRowIndex, "hhliner");
            udc_comCode_Grid.setSelectId("retrieveClntPicInfo");
            udc_comCode_Grid.ilCommonPopUp(scwin.callbackLinerPic,
                ds_srList.getCellData(0, "hhlinerattn"),
                ds_srList.getCellData(0, "hhlinerattnnm"),
                chgGubun, '4', "Liner PIC", '100,350',
                null, pParam, '500', '500', null, null, null,
                "T", null);
            break;
    }
};

scwin.callbackLinerPic = function(rtnList) {
    let row = 0;
    if (rtnList != null && rtnList.length >= 2) {
        ds_srList.setCellData(row, "hhlinerattn", rtnList[0]);
        ds_srList.setCellData(row, "hhlinerattnnm", rtnList[1]);
    }
};

