scwin.f_RunExcel1 = async function () {
    let totCnt = ds_ocContList.getRowCount();
    let sheetTitle  = "Container List_" + $c.date.getServerDateTime("yyyyMMdd");

    if(totCnt != 0){            
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            const options = {
                fileName: sheetTitle + ".xlsx", 
                sheetName: sheetTitle,
                type: "4 + 8 + 16"
            };

            $c.data.downloadGridViewExcel(gr_ocContList, options, []);    
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);    
    }
};

scwin.f_RunExcel2 = async function () {
    let totCnt = ds_ocElList.getRowCount();
    let sheetTitle  = "수출신고 List_" + $c.date.getServerDateTime("yyyyMMdd");

    if(totCnt != 0){            
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
        if (cfrm) {
            const options = {
                fileName: sheetTitle + ".xlsx", 
                sheetName: sheetTitle,
                type: "4 + 8 + 16"
            };

            $c.data.downloadGridViewExcel(gr_ocElList, options, []);    
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);    
    }
};

